mapper.select:
SELECT perm.id, perm.user_id, usr.username, usr.real_name, perm.skill_id, sk.skill_name,
       perm.can_view, perm.can_use, perm.can_train, perm.can_publish, perm.status, perm.grant_time
FROM ai_user_skill_permission perm
INNER JOIN sys_user usr ON usr.id = perm.user_id AND usr.is_deleted = FALSE
INNER JOIN ai_skill sk ON sk.id = perm.skill_id AND sk.is_deleted = FALSE
WHERE 1 = 1
AND perm.user_id = #{request.userId}
AND perm.skill_id = #{request.skillId}
AND perm.status = #{request.status}
ORDER BY perm.grant_time DESC, perm.id DESC
